import React, { useState, useEffect } from 'react';
import PatientForm from './components/PatientForm';
import ResultCard from './components/ResultCard';
import AnalyticsDashboard from './components/AnalyticsDashboard';
import './App.css';

function App() {
  const [result, setResult] = useState(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState(null);
  const [analytics, setAnalytics] = useState(null);

  useEffect(() => {
    // Force scroll to top and prevent browser scroll restoration
    const scrollToTop = () => {
      window.scrollTo(0, 0);
      document.documentElement.scrollTop = 0;
      document.body.scrollTop = 0;
    };
    
    // Execute immediately
    scrollToTop();
    
    // Also execute after a short delay to ensure it works
    setTimeout(scrollToTop, 100);
    
    // Fetch analytics data on component mount and after predictions
    fetchAnalytics();
  }, []);

  const fetchAnalytics = async () => {
    try {
      const response = await fetch('http://localhost:5000/analytics');
      if (response.ok) {
        const data = await response.json();
        setAnalytics(data);
      }
    } catch (err) {
      console.error('Failed to fetch analytics:', err);
    }
  };

  const handleSubmit = async (formData) => {
    setLoading(true);
    setError(null);
    setResult(null);

    try {
      const response = await fetch('http://localhost:5000/predict', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify(formData),
      });

      if (!response.ok) {
        const errorData = await response.json();
        throw new Error(errorData.error || 'Prediction failed');
      }

      const data = await response.json();
      setResult(data);
      // Refresh analytics after prediction
      fetchAnalytics();
    } catch (err) {
      setError(err.message);
    } finally {
      setLoading(false);
    }
  };

  const handleReset = () => {
    setResult(null);
    setError(null);
  };

  const [formResetFunction, setFormResetFunction] = useState(null);

  const handleDownloadReport = async () => {
    if (!result) return;
    
    try {
      const response = await fetch('http://localhost:5000/download_report', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify(result),
      });

      if (!response.ok) {
        const errorData = await response.json();
        throw new Error(errorData.error || 'Report generation failed');
      }

      const data = await response.json();
      
      // Create download link
      const link = document.createElement('a');
      link.href = `data:${data.report.mime_type};base64,${data.report.content}`;
      link.download = data.report.filename;
      document.body.appendChild(link);
      link.click();
      document.body.removeChild(link);
    } catch (err) {
      setError(err.message);
    }
  };

  return (
    <div className="App">
      <div className="container">
        <header className="app-header">
          <h1>🏥 Patient Readmission Predictor</h1>
          <p>AI-Powered Risk Assessment for Hospital Readmission</p>
        </header>

        <main className="main-content">
          {/* Analytics Dashboard */}
          {analytics && (
            <div className="card analytics-section">
              <AnalyticsDashboard analytics={analytics} />
            </div>
          )}

          <div className="card">
            <PatientForm onSubmit={handleSubmit} loading={loading} onReset={setFormResetFunction} />
            
            {error && (
              <div className="error-message">
                <strong>Error:</strong> {error}
                <button onClick={() => { handleReset(); if (formResetFunction) formResetFunction(); }} className="retry-btn">
                  Try Again
                </button>
              </div>
            )}
          </div>

          {result && (
            <div className="card">
              <ResultCard result={result} loading={loading} />
              <div className="action-buttons">
                <button onClick={handleDownloadReport} className="download-btn">
                  📄 Download Risk Report
                </button>
                <button onClick={() => { handleReset(); if (formResetFunction) formResetFunction(); }} className="new-prediction-btn">
                  New Prediction
                </button>
              </div>
            </div>
          )}
        </main>

        <footer className="app-footer">
          <p>
            This tool uses machine learning to predict 30-day readmission risk. 
            Always consult with healthcare professionals for medical decisions.
          </p>
        </footer>
      </div>
    </div>
  );
}

export default App;
